const items = $input.all();

// Group responses by rating
const groupedByRating = {
  positive: [],
  neutral: [],
  negative: []
};

for (const item of items) {
  // Google Sheetの日本語列名を正しく参照するように修正
  const rating = parseInt(item.json["満足度 (Rating)"] || 0);
  const feedback = item.json["自由記述コメント (Comment)"] || '';
  const date = item.json["回答日時 (Timestamp)"] || new Date().toISOString();

  const response = {
    rating: rating,
    feedback: feedback,
    date: date
  };

  // --- ここから修正 ---
  // 5段階評価に合わせて感情を分類
  if (rating >= 4) {
    // 4点以上なら "positive"
    groupedByRating.positive.push(response);
  } else if (rating === 3) {
    // 3点なら "neutral"
    groupedByRating.neutral.push(response);
  } else {
    // 3点未満なら "negative"
    groupedByRating.negative.push(response);
  }
  // --- ここまで修正 ---
}

// Prepare batches for AI processing
const batches = [];

for (const [sentiment, responses] of Object.entries(groupedByRating)) {
  if (responses.length > 0) {
    batches.push({
      sentiment: sentiment,
      count: responses.length,
      responses: responses.slice(0, 50) // 1バッチあたりの回答数を50に制限
    });
  }
}

return batches;

